    45→    // Timeout helper to prevent infinite loading
    46→    function withTimeout<T>(promise: PromiseLike<T>, ms: number, label: string): Promise<T> {
    47→        return Promise.race([
    48→            promise as Promise<T>,
    49→            new Promise<T>((_, reject) =>
    50→                setTimeout(() => reject(new Error(`${label} timed out after ${ms}ms`)), ms)
