    86→                            account_type: entityType
    87→                        }
    88→                    }),
    89→                    5000, // Short timeout for non-critical update
    90→                    "Auth Update"
    91→                );
    92→            } catch (authWarn) {
    93→                console.warn("[Settings] Auth metadata update failed or timed out (continuing):", authWarn);
    94→            }
    95→
    96→            // 3. Update/Create Profile (Critical Path)
    97→            console.log("[Settings] Updating Profile...", profile ? "Update" : "Create");
    98→            if (profile) {
    99→                await withTimeout(updateProfile(data), 10000, "Profile Update");
   100→            } else {
