     3→import { useState, useEffect } from "react";
     4→import type { AnalysisOutput } from "@/lib/analysis/types";
     5→
     6→export interface StoredProject {
     7→    id: string;
     8→    title: string;
     9→    text: string;
    10→    description: string;
    11→    globalScore: number;
    12→    recommendation: "GO" | "EXPLORE" | "PARK" | "KILL";
    13→    confidenceLevel: "LOW" | "MEDIUM" | "HIGH";
    14→    analysis: {
    15→        axes: Array<{ label: string; score: number; justification?: string }>;
    16→        synthesis: string;
    17→        risks: string[];
    18→    };
    19→    timestamp: string;
    20→    isDemo: boolean;
    21→    fullResult?: AnalysisOutput;
    22→}
    23→
    24→export function useProject(id: string | undefined) {
    25→    const [project, setProject] = useState<StoredProject | null>(null);
    26→    const [isLoading, setIsLoading] = useState(true);
    27→
    28→    useEffect(() => {
    29→        if (!id) {
    30→            setIsLoading(false);
    31→            return;
    32→        }
    33→
    34→        // Try k3rn_projects first
    35→        const projectsRaw = localStorage.getItem("k3rn_projects");
    36→        if (projectsRaw) {
    37→            try {
    38→                const projects: any[] = JSON.parse(projectsRaw);
    39→                const found = projects.find((p) => p.id === id);
    40→                if (found) {
    41→                    setProject(normalizeProject(found));
    42→                    setIsLoading(false);
    43→                    return;
    44→                }
    45→            } catch { /* ignore parse errors */ }
    46→        }
    47→
    48→        // Fallback: k3rn_active_project
    49→        const activeRaw = localStorage.getItem("k3rn_active_project");
    50→        if (activeRaw) {
    51→            try {
    52→                const active = JSON.parse(activeRaw);
    53→                if (active.id === id) {
    54→                    setProject(normalizeProject(active));
    55→                    setIsLoading(false);
    56→                    return;
    57→                }
    58→            } catch { /* ignore parse errors */ }
    59→        }
    60→
    61→        setIsLoading(false);
    62→    }, [id]);
    63→
    64→    return { project, isLoading };
    65→}
    66→
    67→function normalizeProject(raw: any): StoredProject {
    68→    return {
    69→        id: raw.id || "",
    70→        title: raw.title || raw.text || "Untitled",
    71→        text: raw.text || "",
    72→        description: raw.description || raw.text || "",
    73→        globalScore: raw.globalScore ?? raw.viabilityScore ?? 0,
    74→        recommendation: raw.recommendation ?? raw.classification ?? "EXPLORE",
    75→        confidenceLevel: raw.confidenceLevel ?? "MEDIUM",
    76→        analysis: {
    77→            axes: raw.analysis?.axes ?? [],
    78→            synthesis: raw.analysis?.synthesis ?? "",
    79→            risks: raw.analysis?.risks ?? [],
    80→        },
    81→        timestamp: raw.timestamp || new Date().toISOString(),
    82→        isDemo: raw.isDemo ?? false,
    83→        fullResult: raw.fullResult ?? undefined,
    84→    };
    85→}
