     7→interface WorkflowState {
     8→    workflow: {
     9→        id: string;
    10→        currentStep: number;
    11→        totalSteps: number;
    12→        status: string;
    13→        labId: string;
    14→        completedSteps: any[];
    15→    };
    16→    definition: {
    17→        steps: {
    18→            id: string;
    19→            title: string;
    20→            description: string;
    21→            type: string;
    22→        }[];
    23→    };
    24→}
    25→
    26→export function useWorkflow(dossierId: string | undefined) {
    27→    const [data, setData] = useState<WorkflowState | null>(null);
    28→    const [isLoading, setIsLoading] = useState(true);
    29→    const [error, setError] = useState<string | null>(null);
    30→
    31→    useEffect(() => {
    32→        if (!dossierId) {
    33→            setIsLoading(false);
    34→            return;
    35→        }
    36→
    37→        async function fetchWorkflow() {
    38→            try {
    39→                const res = await fetch(`/api/workflow?dossierId=${dossierId}`);
    40→                if (!res.ok) throw new Error('Failed to fetch workflow');
    41→                const json = await res.json();
    42→
    43→                if (json.workflow) {
    44→                    setData(json);
    45→                } else {
    46→                    setData(null);
    47→                }
    48→            } catch (err) {
    49→                console.error(err);
    50→                setError('Could not load workflow');
    51→            } finally {
    52→                setIsLoading(false);
    53→            }
    54→        }
    55→
    56→        fetchWorkflow();
    57→    }, [dossierId]);
    58→
    59→    // Function to force refresh (e.g. after XO action)
    60→    const refresh = async () => {
    61→        if (!dossierId) return;
    62→        setIsLoading(true);
    63→        try {
    64→            const res = await fetch(`/api/workflow?dossierId=${dossierId}`);
    65→            const json = await res.json();
    66→            if (json.workflow) setData(json);
    67→        } catch (err) {
    68→            console.error(err);
    69→        } finally {
    70→            setIsLoading(false);
    71→        }
    72→    };
    73→
    74→    return { ...data, isLoading, error, refresh };
    75→}
