    31→function getWelcomeMessage(project: StoredProject | null, labType: "discovery" | "structuration" | "validation"): string {
    32→    if (!project) {
    33→        if (labType === "discovery") return "Bonjour ! Je suis Ava, votre experte Discovery. Chargez un projet pour que je puisse vous aider à l'explorer.";
    34→        if (labType === "validation") return "Bonjour ! Je suis Sarah, votre Market Validator. Chargez un projet pour que j'analyse son potentiel marché.";
    35→        return "Bonjour ! Je suis Marcus, votre expert Structuration. Chargez un projet pour commencer à bâtir.";
