    41→            return score < 60;
    42→        });
    43→        const weakList = weakAxes.map((a) => a.label).join(", ");
    44→        return `Bonjour ! Je suis **Ava**, votre experte Discovery. J'ai analysé votre projet **"${project.title}"** — score global de **${project.globalScore}/100** (${project.recommendation}).${weakAxes.length > 0
    45→                ? ` Je remarque des axes à approfondir : **${weakList}**. Commençons par challenger vos hypothèses sur ces points.`
    46→                : ` Le profil est solide. Explorons ensemble les angles morts potentiels.`
    47→            } Quelle question souhaitez-vous explorer en premier ?`;
