    75→    const [processingTool, setProcessingTool] = useState(false);
    76→    const chatEndRef = useRef<HTMLDivElement>(null);
    77→    const textareaRef = useRef<HTMLTextAreaElement>(null);
    78→
    79→    // Load messages from localStorage
    80→    useEffect(() => {
    81→        const stored = localStorage.getItem(storageKey);
    82→        if (stored) {
    83→            try {
    84→                const parsed = JSON.parse(stored);
    85→                if (Array.isArray(parsed) && parsed.length > 0) {
    86→                    setMessages(parsed);
    87→                    return;
    88→                }
    89→            } catch { /* ignore */ }
    90→        }
    91→        // Set welcome message
    92→        setMessages([{ role: "assistant", content: getWelcomeMessage(project, labType) }]);
    93→    }, [storageKey, project, labType]);
    94→
    95→    // Save messages to localStorage
    96→    useEffect(() => {
    97→        if (messages.length > 0) {
    98→            localStorage.setItem(storageKey, JSON.stringify(messages));
    99→        }
   100→    }, [messages, storageKey]);
   101→
   102→    // Auto-scroll
   103→    useEffect(() => {
   104→        chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
   105→    }, [messages, isStreaming, processingTool]);
   106→
   107→    // Tool Detection & Execution
   108→    useEffect(() => {
   109→        if (!isStreaming && messages.length > 0) {
   110→            const lastMsg = messages[messages.length - 1];
   111→            if (lastMsg.role === "assistant" && !processingTool) {
   112→                // Check for commands
   113→                const redditMatch = lastMsg.content.match(/\[REDDIT_SEARCH:\s*(.*?)\]/);
   114→                const trendsMatch = lastMsg.content.match(/\[GOOGLE_TRENDS:\s*(.*?)\]/);
   115→
   116→                if (redditMatch) {
   117→                    executeTool("reddit", redditMatch[1]);
   118→                } else if (trendsMatch) {
   119→                    executeTool("trends", trendsMatch[1]);
   120→                }
   121→            }
   122→        }
   123→    }, [isStreaming, messages, processingTool]);
   124→
   125→    async function executeTool(tool: "reddit" | "trends", query: string) {
   126→        setProcessingTool(true);
   127→        const endpoint = tool === "reddit" ? "/api/external/reddit" : "/api/external/trends";
   128→        const body = tool === "reddit" ? { query } : { keyword: query };
   129→
   130→        // Add visual indicator
   131→        setMessages(prev => [...prev, { role: "system", content: `Exécution de l'outil ${tool}...` }]);
   132→
   133→        try {
   134→            const res = await fetch(endpoint, {
   135→                method: "POST",
   136→                body: JSON.stringify(body),
   137→                headers: { "Content-Type": "application/json" }
   138→            });
   139→            const data = await res.json();
   140→
   141→            // Format result for LLM
   142→            const resultMsg = `[SYSTEM DATA] Résultat pour ${tool} "${query}":\n${JSON.stringify(data, null, 2)}`;
   143→
   144→            // Updates messages with result and triggers continuation
   145→            setMessages(prev => {
   146→                const newMsgs = [...prev];
   147→                // Remove the "Exécution..." message
   148→                if (newMsgs[newMsgs.length - 1].role === "system") newMsgs.pop();
   149→                return [...newMsgs, { role: "system" as const, content: resultMsg }];
   150→            });
   151→
   152→            // Trigger AI response automatically
   153→            setTimeout(() => sendMessage(resultMsg, true), 500);
   154→
   155→        } catch (error) {
   156→            console.error("Tool execution failed", error);
   157→            setMessages(prev => [...prev, { role: "system" as const, content: `Erreur outil: ${error}` }]);
   158→        } finally {
   159→            setProcessingTool(false);
   160→        }
   161→    }
   162→
   163→    const sendMessage = useCallback(async (contentOverride?: string, isSystemTrigger = false) => {
   164→        const text = contentOverride || input.trim();
   165→        if (!text && !isSystemTrigger) return;
   166→        if (isStreaming || rateLimited) return;
   167→
   168→        if (!isSystemTrigger) setInput("");
   169→        setStreamError(null);
   170→
   171→        // If it's a user message, add it. If it's system trigger, it's already added or we handle it differently.
   172→        // Actually for system trigger, we assume the message is already in state (system role).
   173→        // BUT the API expects messages list. 
   174→        // If isSystemTrigger is true, we don't add a user message, we just send existing messages + trigger.
   175→        // Wait, if I call sendMessage with resultMsg, I want to ADD it?
   176→        // In executeTool I already added the SYSTEM message.
   177→        // So I just need to call API with current messages.
   178→
   179→        const currentMessages = isSystemTrigger ? messages : [...messages, { role: "user" as const, content: text }];
   180→
   181→        if (!isSystemTrigger) {
   182→            setMessages(currentMessages);
   183→        }
   184→
   185→        setIsStreaming(true);
   186→
   187→        // Build project context
   188→        const projectContext = project ? {
   189→            title: project.title,
   190→            description: project.description,
   191→            globalScore: project.globalScore,
   192→            recommendation: project.recommendation,
   193→            confidenceLevel: project.confidenceLevel,
   194→            axes: project.analysis.axes,
   195→            synthesis: project.analysis.synthesis,
   196→            risks: project.analysis.risks,
   197→            levers: project.fullResult?.levers?.map((l: any) => ({
   198→                axis: l.axis,
   199→                action: l.action,
   200→                expected_impact: l.expected_impact,
   201→            })),
   202→        } : {
   203→            title: "Projet inconnu",
   204→            description: "",
   205→            globalScore: 0,
   206→            recommendation: "EXPLORE",
   207→            confidenceLevel: "LOW",
   208→            axes: [],
   209→            synthesis: "",
   210→            risks: [],
   211→        };
   212→
   213→        try {
   214→            const response = await fetch("/api/expert-chat", {
   215→                method: "POST",
   216→                headers: { "Content-Type": "application/json" },
   217→                body: JSON.stringify({
   218→                    messages: currentMessages.map(m => ({
   219→                        role: m.role === "system" ? "user" : m.role, // Claude doesn't support system messages in messages list usually, map to user
   220→                        content: m.content
   221→                    })),
   222→                    projectContext,
   223→                    labType,
   224→                    language: currentLang,
   225→                }),
   226→            });
   227→
   228→            if (response.status === 429) {
   229→                setRateLimited(true);
   230→                setStreamError("Limite de requêtes atteinte. Réessayez dans quelques instants.");
   231→                setTimeout(() => setRateLimited(false), 30000);
   232→                setIsStreaming(false);
   233→                return;
   234→            }
   235→
   236→            if (!response.ok) {
   237→                throw new Error(`Erreur ${response.status}`);
   238→            }
   239→
   240→            const reader = response.body?.getReader();
   241→            if (!reader) throw new Error("No reader");
   242→
   243→            const decoder = new TextDecoder();
   244→            let assistantContent = "";
   245→
   246→            // Add empty assistant message
   247→            setMessages((prev) => [...prev, { role: "assistant", content: "" }]);
   248→
   249→            while (true) {
   250→                const { done, value } = await reader.read();
   251→                if (done) break;
   252→
   253→                const chunk = decoder.decode(value, { stream: true });
   254→                const lines = chunk.split("\n");
   255→
   256→                for (const line of lines) {
   257→                    if (!line.startsWith("data: ")) continue;
   258→                    const data = line.slice(6).trim();
   259→                    if (data === "[DONE]") continue;
   260→
   261→                    try {
   262→                        const parsed = JSON.parse(data);
   263→                        if (parsed.error) {
   264→                            if (parsed.error === "rate_limited") {
   265→                                setRateLimited(true);
   266→                                setStreamError("Limite de requêtes atteinte.");
   267→                                setTimeout(() => setRateLimited(false), 30000);
   268→                            } else {
   269→                                setStreamError("Erreur de connexion. Le message partiel est conservé.");
   270→                            }
   271→                            break;
   272→                        }
   273→                        if (parsed.text) {
   274→                            assistantContent += parsed.text;
   275→                            setMessages((prev) => {
   276→                                const updated = [...prev];
   277→                                updated[updated.length - 1] = { role: "assistant", content: assistantContent };
   278→                                return updated;
   279→                            });
   280→                        }
   281→                    } catch { /* ignore malformed chunks */ }
   282→                }
   283→            }
   284→        } catch (error: any) {
   285→            setStreamError("Erreur de connexion. Vérifiez votre connexion internet.");
   286→            // Keep partial content if any
   287→            setMessages((prev) => {
   288→                const last = prev[prev.length - 1];
   289→                if (last?.role === "assistant" && !last.content) {
   290→                    return prev.slice(0, -1); // Remove empty assistant message
   291→                }
   292→                return prev;
   293→            });
   294→        } finally {
   295→            setIsStreaming(false);
   296→        }
   297→    }, [input, isStreaming, rateLimited, messages, project, labType, currentLang]);
