    80→                        question: "Quelle experience specifique avez-vous dans ce domaine ? Quelles competences manquent a l'equipe ?",
    81→                        context: axis.justification,
    82→                        severity,
    83→                    });
    84→                }
    85→            }
    86→        }
    87→
    88→        // Questions from risks
    89→        for (const risk of risks) {
    90→            if (risk.severity === "HIGH") {
    91→                const label = risk.axis.charAt(0).toUpperCase() + risk.axis.slice(1).replace("_", " ");
    92→                questions.push({
    93→                    axis: label,
    94→                    question: `Comment comptez-vous mitiger ce risque : "${risk.description}" ?`,
    95→                    context: risk.description,
    96→                    severity: "HIGH",
    97→                });
    98→            }
    99→        }
   100→    } else {
   101→        // Fallback for projects without fullResult
   102→        for (const axis of project.analysis.axes) {
   103→            const score = axis.score <= 10 ? axis.score * 10 : axis.score;
   104→            if (score < 60) {
   105→                questions.push({
   106→                    axis: axis.label,
   107→                    question: `L'axe "${axis.label}" est faible (${score}/100). Quelles actions concretes envisagez-vous ?`,
   108→                    context: axis.justification || "Score insuffisant",
   109→                    severity: score < 40 ? "HIGH" : "MEDIUM",
   110→                });
   111→            }
   112→        }
   113→    }
   114→
   115→    return questions;
   116→}
