    30→    const [responses, setResponses] = useState<Map<string, EnrichmentResponse>>(new Map());
    31→    const [selectedOptions, setSelectedOptions] = useState<Set<string>>(new Set());
    32→    const [recalcResult, setRecalcResult] = useState<any>(null);
    33→
    34→    // Generate questions on mount
    35→    useEffect(() => {
    36→        generateQuestions();
